function YouTubePlayer() {
  const [videoId, setVideoId] = React.useState('REPLACE_WITH_VIDEO_ID');
  const [input, setInput] = React.useState('REPLACE_WITH_VIDEO_ID');

  const extractId = (url) => {
    const m = url.match(/(?:v=|\/)([a-zA-Z0-9_-]{11})/);
    return m ? m[1] : url;
  };

  const load = () => {
    const id = extractId(input);
    setVideoId(id);
  };

  return (
    <div style={{padding:12,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{display:'flex',gap:8,marginBottom:10}}>
        <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>e.key==='Enter'&&load()}
          style={{flex:1,padding:'8px 12px',borderRadius:8,border:'1px solid #ccc',fontSize:14}}
          placeholder="YouTube URL or video ID…"/>
        <button onClick={load}
          style={{padding:'8px 16px',borderRadius:8,background:'#FF0000',color:'#fff',border:'none',cursor:'pointer',fontWeight:600}}>
          Play
        </button>
      </div>
      <div style={{flex:1,position:'relative',borderRadius:12,overflow:'hidden',background:'#000'}}>
        {videoId && (
          <iframe
            src={`https://www.youtube.com/embed/${videoId}?rel=0`}
            style={{width:'100%',height:'100%',border:'none'}}
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
            allowFullScreen
          />
        )}
      </div>
    </div>
  );
}
render(<YouTubePlayer/>);
